import React from "react";
import "./style.css";

function goToSignin() {
            window.parent.location.href = "/signin";
        }

function Home(){
    return(
        <>
            <section className="homecontainer">
                <h1 style="font-size: 50px;">Welcome to GlucoGuide</h1>
                <h1 class="h1Style">Your personal companion for diabetes-friendly nutrition and emotional wellness.</h1>
                <p class="homepara">Track Diabetes Through Lifestyle & Emotions</p>
                <p class="homepara">You can check your weekly report</p>
                <button onClick="goToSignin()">Get Started</button><br/><br/><br/>


            </section>
        </>
    );
}

export default Home;
